const menu = [
  {
    categoryId: 'pizza_cheese',
    categoryName: { en: 'Cheese Pizza', ar: 'بيتزا الجبن' },
    items: [
      {
        id: 'pizza_margherita',
        name: { en: 'Pizza Margherita', ar: 'بيتزا مارجرينا' },
        description: {
          en: 'Classic tomato sauce, mozzarella, basil',
          ar: 'صلصة بيتزا، جبنة موتزاريلا، ريحان',
        },
        prices: { small: 105, large: 130 },
      },
      {
        id: 'pizza_green',
        name: { en: 'Green Pizza', ar: 'بيتزا خضروات' },
        description: {
          en: 'Tomato sauce, mozzarella, vegetables, mint',
          ar: 'صلصة بيتزا، جبنة موتزاريلا، خضراوات، نعناع',
        },
        prices: { small: 110, large: 140 },
      },
      {
        id: 'pizza_cheese_deluxe',
        name: { en: 'Cheese Pizza Deluxe', ar: 'بيتزا تشيز ديلوكس' },
        description: {
          en: 'Special cheese with tomato sauce and herbs',
          ar: 'جبنة مميزة مع صلصة طماطم وأعشاب',
        },
        prices: { small: 125, large: 150 },
      }
    ]
  },
  {
    categoryId: 'pizza_meat',
    categoryName: { en: 'Meat Pizza', ar: 'بيتزا اللحوم' },
    items: [
      {
        id: 'bastermo_pizza',
        name: { en: 'Bastermo Pizza', ar: 'بيتزا باستيرمو' },
        description: {
          en: 'Bastermo with mozzarella and spicy sauce',
          ar: 'بسترمو مع جبنة موتزاريلا وصلصة حارة',
        },
        prices: { small: 140, large: 165 },
      },
      // more pizzas...
    ],
  },
  // Other categories like chicken pizza, sandwiches, crepes, mixes, additions...
